import { AIProjectsClient } from '@azure/ai-projects';
import { VexClient } from 'vex-sdk';

const client = new AIProjectsClient(credential, {
  subscriptionId: 'your-sub-id',
  resourceGroup: 'rg-agent-service',
  projectName: 'rag-pipeline-project'
});

const vex = new VexClient({ apiKey: 'vex-api-key' });

const thread = await client.agents.get('rag-agent').threads.create();

// Add Vex as thread middleware
thread.addMiddleware(vex.guardrail({
  checks: ['source_faithfulness', 'hallucination_detection', 'citation_accuracy']
}));

const response = await thread.sendMessage(userQuery);

async function assembleContext(chunks: SearchChunk[], maxTokens: number = 8000) {
  let context = '';
  const tokenizer = await getTokenizer('gpt-4');

  for (const chunk of chunks) {
    const candidate = context + '\n\n' + chunk.content;

    if (tokenizer.encode(candidate).length > maxTokens) {
      // Vex triggers summarization
      const summary = await vex.summarize(chunk.content, { maxTokens: 500 });
      context += '\n\n' + summary;
    } else {
      context = candidate;
    }
  }

  return vex.validateContext(context, { relevance_threshold: 0.7 });
}

