      threshold: 0.8
    },
    {
      name: 'citation_accuracy',
      requireAll: true
    }
  ]
});

if (!guardResults.passed) {
  throw new Error(`Guardrail failed: ${guardResults.failures}`);
}

// Attach verified citations
llmOutput.citations = guardResults.validCitations;

